def summarize(rows):
    n_accept = n_reject = n_review = 0
    for r in rows:
        s = r.get("status")
        if s == "accept":
            n_accept += 1
        elif s == "reject":
            n_reject += 1
        elif s == "review":
            n_review += 1
    n_total = len(rows)
    tasa = (n_reject / n_total) if n_total else None
    return {
        "n_accept": n_accept,
        "n_reject": n_reject,
        "n_review": n_review,
        "n_total": n_total,
        "tasa_reject": tasa,
    }

print(summarize([
    {"status": "accept"}, {"status": "reject"}, {"status": "review"}, {"status": "accept"},
]))
print(summarize([]))

# Pipeline mental: por cada fila validar → status → contadores → tasa
# No mezclar n_total con solo accepts.

def pipeline(rows):
    statuses = []
    for r in rows:
        edad = r.get("edad")
        if edad is None:
            st = "review"
        elif not isinstance(edad, int) or edad < 0:
            st = "reject"
        elif edad < 18:
            st = "review"
        else:
            st = "accept"
        statuses.append(st)
    n_total = len(statuses)
    n_reject = statuses.count("reject")
    return {
        "statuses": statuses,
        "n_total": n_total,
        "tasa_reject": (n_reject / n_total) if n_total else None,
    }

print(pipeline([{"edad": 30}, {"edad": None}, {"edad": -1}]))

