# Preferir un dict/set para membership O(1) promedio en vez de doble for
seen = set()
dups = []
for x in ["C1", "C2", "C1", "C3"]:
    if x in seen:
        dups.append(x)
    else:
        seen.add(x)
print("dups", dups)
print("nota: un set evita O(n^2) de buscar en lista anidada")
